def _looks_like_output_shape_fallback(text: str) -> bool:
    normalized = _normalize(text)
    return any(snippet in str(text or "") for snippet in OUTPUT_SHAPE_BANNED_FALLBACKS) or any(
        marker in normalized
        for marker in (
            "기분을은",
            "계획을은",
            "잠을은",
            "쌓여야는",
            "쉬어야는",
        )
    )


