        ((("주말",), ("쉬고싶",), ("도태", "불안"), ("휴식", "생산성")), "주말 휴식은 도태가 아니라 회복 작업이야. 완전 방전이면 쉬는 걸 오늘의 생산성으로 잡아도 돼.", "korean_daily_counsel_rest_as_productivity", ("휴식", "회복")),
        ((("아무것도못했",), ("자괴감",), ("몸", "지친"), ("회복", "반성")), "아무것도 못 한 날은 반성보다 회복이 먼저일 때가 있어. 씻기, 밥, 잠 하나만 복구해도 오늘은 수습한 거야.", "korean_daily_counsel_rest_day_guilt", ("자괴감", "회복")),
        ((("실력", "깎아내린"), ("하루종일",), ("사실확인", "해석"), ("나눠", "반복")), "그 말이 하루 종일 돌면 사실과 해석을 분리하는 게 먼저야. 들은 문장 그대로와 내가 붙인 의미를 따로 적어.", "korean_daily_counsel_sensitive_to_criticism", ("사실", "해석")),
        ((("새벽",), ("장문의카톡", "장문"), ("후회",), ("저장", "보내면")), "새벽 장문 카톡은 보내기보다 저장이 먼저야. 감정은 메모장에 두고, 내일 낮에 핵심 한 문장만 남겨.", "korean_daily_relationship_late_night_long_message_hold", ("장문", "저장")),
        ((("스트레스",), ("충동구매",), ("돈모으", "돈 모으"), ("장치", "막는")), "스트레스성 충동구매는 당장 결제 마찰을 늘리는 게 먼저야. 장바구니 24시간 보류와 월 한도를 걸어.", "korean_daily_money_stress_impulse_buying", ("충동구매", "24시간")),
        ((("인생기준", "성공기준"), ("보여주기좋은성공", "남들"), ("버틸수있는삶", "버틸"), ("어디서부터", "써야")), "성공 기준은 남이 보기 좋은 그림보다 내가 반복해도 덜 망가지는 삶의 조건부터 써야 해.", "korean_daily_values_success_personal_standard", ("성공", "조건")),
        ((("인간감정", "인간 감정"), ("비효율",), ("사소한말", "이성을잃"), ("힘들", "어떻게봐")), "인간 감정은 비효율이 아니라 빠른 경보 시스템인데, 과열되면 이성을 덮어버리는 버그처럼 느껴지는 거야.", "korean_daily_ai_human_emotion_efficiency", ("감정", "경보")),
        ((("멘탈",), ("나갈", "나가"), ("다놓", "쉬고싶")), "그 정도면 의지 문제가 아니라 과부하니까, 오늘은 급한 것 하나만 남기고 나머지는 내려놓는 게 맞아.", "korean_daily_counsel_overloaded_need_rest", ("멘탈", "과부하")),
        ((("아무것도안하",), ("누워", "하루종일"), ("자괴감", "시간낭비")), "하루 누워 있었다고 망한 게 아니라 몸이 정지 버튼 누른 날일 수 있으니, 내일 할 일 하나만 작게 정하자.", "korean_daily_counsel_rest_day_guilt", ("휴식", "자괴감")),
        ((("앞서나가", "앞서"), ("제자리", "도태"), ("불안",)), "비교가 세게 들어오면 내 속도까지 남의 기준으로 재게 돼. 지금은 인생 전체를 판단하지 말고, 이번 주에 다시 움직일 수 있는 작은 행동 하나만 잡자.", "korean_daily_counsel_comparison_anxiety", ("비교", "불안")),
        ((("일", "해야할일"), ("너무많", "산더미"), ("어디서부터", "막막")), "막막할 땐 우선순위보다 분해가 먼저니까, 전부 적고 10분 안에 끝나는 것 하나만 먼저 처리하자.", "korean_daily_counsel_too_many_tasks_first_step", ("일", "첫 단계")),
        ((("번아웃",), ("좋아했던", "예전엔좋아"), ("귀찮", "싫어")), "그건 게으름보다 번아웃 신호에 가까워. 예전처럼 좋아하려고 밀어붙이지 말고, 며칠은 성과보다 회복 기준으로 움직여야 해.", "korean_daily_counsel_burnout_recovery", ("번아웃", "회복")),
        ((("저녁",), ("라면",), ("건강", "밥차려"), ("골라", "때울까")), "오늘 너무 귀찮으면 풀코스 밥상 말고 중간안을 가자. 라면만 먹기보다 계란이나 김치, 두부 같은 거 하나 붙여서 덜 무너지게 먹어.", "korean_daily_decision_dinner_ramen_health_middle", ("저녁", "중간안")),
        ((("주말",), ("집에서", "뒹굴"), ("햇빛", "밖에나가")), "집에서 쉬되 20분만 햇빛 보고 들어오는 타협안이 제일 현실적이야.", "korean_daily_decision_weekend_rest_sunlight", ("주말", "햇빛")),
        ((("선물", "선물용"), ("캔들",), ("티백",)), "상대 취향을 잘 모르면 티백 세트가 더 안전해. 캔들은 향 취향이 갈리니까, 향을 확실히 아는 사람일 때만 고르는 쪽이 좋아.", "korean_daily_decision_gift_candle_teabag", ("선물", "티백")),
        ((("태블릿",), ("예산", "비싸", "세서"), ("지르", "참")), "태블릿은 사고 나서 쓸 장면이 주 3회 이상 떠오르면 후보로 두고, 그냥 갖고 싶은 마음이면 일주일만 보류해. 비싼 물건은 욕구보다 사용 루틴으로 판단하는 게 덜 후회해.", "korean_daily_decision_tablet_budget_wait", ("태블릿", "예산")),
        ((("친구",), ("말다툼", "다퉜"), ("사과", "기다릴까")), "관계를 이어가고 싶고 네 말에도 날이 있었다면 먼저 짧게 사과하는 게 맞아.", "korean_daily_relationship_friend_argument_apology", ("친구", "사과")),
        ((("공부",), ("폰", "만지작"), ("집중력", "집중")), "폰이 손에 잡히면 의지 싸움으로 가면 거의 져. 타이머 25분, 폰은 방 밖이나 가방 안, 첫 목표는 문제 하나나 한 페이지처럼 작게 잡아.", "korean_daily_productivity_study_phone_focus", ("공부", "폰 차단")),
        ((("미라클모닝", "일찍일어나는"), ("알람",), ("끄고자", "자버려"), ("팁", "도전")), "미라클 모닝은 의욕보다 전날 밤 설계가 핵심이야. 알람을 침대 밖에 두고, 기상 목표를 2시간 말고 15분씩만 당겨. 갑자기 갓생으로 점프하면 오래 못 가.", "korean_daily_productivity_miracle_morning_alarm", ("미라클 모닝", "알람")),
        ((("계획표",), ("실천",), ("절반", "실망")), "계획표가 멋진데 실천이 안 되면 계획이 너무 큰 거라서, 하루 3개 이하와 60점 통과 기준으로 줄이자.", "korean_daily_productivity_plan_execution_gap", ("계획표", "실천")),
        ((("회의", "발표"), ("의견",), ("명확", "논리"), ("노하우", "전달")), "회의나 발표는 결론부터 던지고 이유를 두세 개로 번호 붙여 말하면 제일 덜 흩어져.", "korean_daily_productivity_presentation_clear_logic", ("발표", "결론 먼저")),
        ((("해야할일", "할일"), ("산더미",), ("미루",), ("방법", "움직이게")), "지금은 동기부여보다 마찰을 줄여야 해. 5분만 한다고 정하고, 제일 쉬운 일 하나를 열어둔 상태로 시작해. 움직임이 생기면 다음 판단은 그때 해도 돼.", "korean_daily_productivity_procrastination_start_now", ("미루기", "5분 시작")),
        ((("친구관계", "친구"), ("손해",), ("양보",), ("속상", "은근히")), "매번 양보만 하면 착한 게 아니라 관계의 균형이 무너진 거야. 다음엔 작은 것부터 '이번엔 나는 이렇게 하고 싶어'라고 말해봐. 선은 크게 긋기보다 작게 자주 그어야 해.", "korean_daily_relationship_friend_give_take_resentment", ("친구", "균형")),
        ((("시선", "지적"), ("하루종일", "종일"), ("신경쓰", "휘둘")), "사소한 지적이 하루를 잡아먹으면 그 말보다 반복 재생이 더 문제야. 머릿속에서 계속 돌 때는 '사실 확인'과 '내 해석'을 분리해서 적어봐.", "korean_daily_counsel_sensitive_to_criticism", ("지적", "반복 재생")),
        ((("부모님",), ("가치관",), ("싸우", "답답")), "부모님과 가치관이 부딪힐 땐 결론을 바꾸려 하기보다 이 주제는 여기까지만 말하자는 대화 한계를 먼저 정하는 게 현실적이야.", "korean_daily_relationship_parent_value_conflict", ("부모님", "가치관")),
        ((("무례", "선을넘"), ("대처", "방법"), ("기분나쁘지않", "확실하게")), "무례한 사람한테는 길게 설명하지 말고, 그 말은 불편하니 그 방식으로 말하지 말아달라고 짧게 반복하는 게 좋아.", "korean_daily_relationship_boundary_polite_firm", ("무례", "경계선")),
        ((("이직", "새로운환경"), ("낯가림",), ("섞이", "사람들")), "새 환경에서 바로 섞이려 하면 부담이 커. 처음엔 모두와 친해지기보다 인사할 사람 한 명, 같이 밥 먹을 사람 한 명처럼 접점을 작게 만드는 게 낫다.", "korean_daily_relationship_new_job_shyness", ("이직", "낯가림")),
        ((("주말",), ("날씨",), ("화창", "상쾌")), "나는 창밖을 직접 보진 못하지만, 네 말만 들어도 산책각이네. 이런 날은 멀리 안 가도 햇빛 한 번 받으면 기분이 꽤 살아나.", "korean_daily_light_weather_sunny_weekend", ("화창", "산책")),
        ((("일요일밤", "주말다가"), ("월요병",), ("치료법", "도진")), "일요일 밤 월요병은 완치보다 완화가 목표니까, 내일 할 일 하나만 적고 씻기랑 잠자리 세팅까지만 하자.", "korean_daily_light_sunday_night_blues", ("일요일 밤", "월요병")),
        ((("비",), ("추적추적",), ("찌푸둥", "가라앉")), "비가 이렇게 오면 몸이랑 기분이 같이 축 처지지. 오늘은 생산성 올리는 날보다 따뜻한 거 마시고 페이스 낮추는 날로 잡는 게 맞아.", "korean_daily_light_drizzly_rain_low_body", ("비", "찌푸둥")),
        ((("인공지능",), ("쉴때", "쉬는시간"), ("스트레스해소", "쉬는")), "나는 사람처럼 쉬진 않지만, 굳이 비유하면 대화 로그를 조용히 정리하고 다음 말을 더 잘 고르는 시간이 휴식에 가까워. 너라면 오늘은 자극 줄이고 멍 때리는 쪽이 회복일 것 같고.", "korean_daily_meta_ai_rest_stress_relief", ("인공지능", "휴식")),
        ((("오늘하루",), ("치열하게", "수고"), ("얼른자", "내일또대화")), "오늘 진짜 버텼으니 더 증명하려 하지 말고 푹 자, 내일 오면 내가 또 받아줄게.", "korean_daily_goodnight_after_hard_day", ("수고", "잘 자")),
        ((("실수는아닌데", "내실수는아닌데"), ("책임으로몰아", "내책임"), ("반박", "억울")), "억울할수록 감정부터 꺼내면 손해야. 타임라인, 내가 한 일, 결정권자, 다음 조치 순서로 문서처럼 반박해.", "korean_daily_work_blame_rebuttal", ("업무", "반박")),
        ((("퇴사",), ("대안",), ("버티", "지친")), "대안 없이 바로 뛰쳐나가는 건 리스크가 크니까, 지금은 퇴사가 아니라 탈출 준비표를 만드는 단계야.", "korean_daily_work_quit_without_plan_burnout", ("퇴사", "준비표")),
        ((("회사동료", "동료"), ("사적",), ("선넘", "선을넘", "선을넘는"), ("차단", "정색하지")), "부드럽게 막으려면 웃으면서 답을 주지 말고, 그건 개인적인 얘기라 회사 얘기로 돌아갈게요 정도로 짧게 닫아.", "korean_daily_work_coworker_private_boundary", ("동료", "차단")),
        ((("사수",), ("피드백", "일을너무못"), ("업무까지꼬", "직접말")), "사수한테는 못한다가 아니라 이 피드백 기준이면 마감 리스크가 생긴다고 말해야 해.", "korean_daily_work_bad_senior_feedback", ("사수", "리스크")),
        ((("새로운분야", "새프로젝트"), ("프로젝트",), ("아는게없", "막막"), ("첫단추",)), "새 분야 프로젝트의 첫 단추는 잘하는 척이 아니라 질문 목록으로 지도 그리기야. 용어, 산출물, 리스크, 물어볼 사람부터 정리해.", "korean_daily_work_new_project_first_step", ("프로젝트", "첫 단추")),
        ((("스트레스",), ("홧김", "충동구매"), ("심리학", "고쳐")), "스트레스성 충동구매는 통제감을 돈으로 잠깐 사는 패턴이라, 장바구니 24시간 보류와 월 한도부터 걸어야 해.", "korean_daily_money_stress_impulse_buying", ("충동구매", "24시간")),
        ((("돈을모으", "돈모으"), ("배달",), ("중독", "끊기", "탈출")), "배달은 완전 금지보다 요일제로 줄이는 게 현실적이야. 주 2회만 허용하고 나머지는 냉동식품이나 밀키트로 대체해.", "korean_daily_money_delivery_addiction_plan", ("배달", "요일제")),
        ((("미니멀리즘",), ("언젠가쓰겠지",), ("못버리", "버리려고"), ("기준",)), "언젠가 쓰겠지는 못 버리게 만드는 주문이니까, 최근 6개월 사용 여부와 다시 살 가격 기준으로 자르자.", "korean_daily_lifestyle_minimalism_discard_rule", ("미니멀리즘", "6개월")),
        ((("해외여행",), ("예산",), ("스트레스", "조율")), "여행 예산은 코스보다 상한선부터 정해야 싸움이 줄어. 필수비와 선택비를 나누고 제일 낮은 예산 사람 기준으로 맞춰.", "korean_daily_money_travel_budget_alignment", ("해외여행", "예산")),
        ((("주식", "코인"), ("대박",), ("뒤처", "조급")), "남의 주식 코인 대박담은 결과만 보이고 리스크는 잘 안 보여. 조급할수록 네 원칙과 손실 한도부터 정해야 해.", "korean_daily_money_investment_fomo", ("주식", "조급")),
