def build_black_draft_utterance(
    *,
    features: MessageFeatures,
    response_plan: ResponsePlan,
    phrasing_plan: PhrasingPlan,
    state: ConversationState | None = None,
) -> dict[str, object]:
    """Build a safe semantic draft before the neural phrasing layer rewrites it."""

    user_text = _compact(features.content, 160)
    anchor = _clean_anchor(response_plan.anchor or _anchor_from_user_text(user_text))
    if _bad_topic_anchor(anchor, user_text=user_text):
        anchor = ""
    must_include = _filter_must_include(
        [_compact(item, 32) for item in response_plan.must_include if _compact(item, 32)],
        user_text=user_text,
        anchor=anchor,
    )
    if _is_hypothetical_choice_text(user_text) or _is_romance_relationship_text(user_text):
        anchor = ""
        must_include = []
    notes = set(response_plan.notes)
    sense_context = _word_sense_context_from_state(state)
    _output_shape_reply, output_shape, output_shape_must_preserve = _render_output_shape_direct_reply(
        user_text,
        sense_context=sense_context,
    )
    draft_frame_detail = _infer_draft_frame_detail(user_text, sense_context=sense_context)
    text = _draft_text(
        action=response_plan.action,
        stance=response_plan.stance,
        anchor=anchor,
        must_include=must_include,
        user_text=user_text,
        notes=notes,
        followup_policy=response_plan.followup_policy,
        sense_context=sense_context,
    )
    draft_direct_reason = _draft_direct_surface_reason(
        user_text=user_text,
        notes=notes,
        draft_reply=text,
        sense_context=sense_context,
    )
    if not draft_direct_reason:
        draft_direct_reason = _structural_draft_direct_reason(
            action=response_plan.action,
            stance=response_plan.stance,
            user_text=user_text,
            sense_context=sense_context,
        )
    if draft_direct_reason:
        anchor = ""
        must_include = []
    else:
        text = _ensure_must_include(text, must_include)
    text = _clip_sentences(text, sentence_budget=response_plan.sentence_budget)
    if not draft_direct_reason:
        draft_direct_reason = _draft_direct_surface_reason(
            user_text=user_text,
            notes=notes,
            draft_reply=text,
            sense_context=sense_context,
        )
        if draft_direct_reason:
            anchor = ""
            must_include = []
    if not draft_direct_reason:
        draft_direct_reason = _structural_draft_direct_reason(
            action=response_plan.action,
            stance=response_plan.stance,
            user_text=user_text,
            sense_context=sense_context,
        )
    daily_reason_metadata = _daily_reason_draft_metadata(draft_direct_reason)
    draft_domain = ""
    if daily_reason_metadata:
        draft_domain, draft_frame_detail = daily_reason_metadata
    draft_action = _daily_reason_action_override(draft_direct_reason) or response_plan.action.value
    output_shape_label = output_shape or _infer_output_shape(user_text)
    semantic_frame = infer_draft_semantic_frame(
        direct_surface_reason=draft_direct_reason,
        output_shape=output_shape_label,
        draft_domain=draft_domain,
        draft_frame_detail=draft_frame_detail,
        action=draft_action,
        tone=response_plan.tone,
    )
    semantic_frame_payload = semantic_frame.to_dict() if semantic_frame is not None else {}
    semantic_frame_payload = _with_money_comparison_focus_axis(
        semantic_frame_payload,
        raw_text=features.content,
        sense_context=sense_context,
    )
    semantic_frame_payload = _with_semantic_relation_candidate_axes(
        semantic_frame_payload,
        raw_text=features.content,
        sense_context=sense_context,
    )
    semantic_frame_payload = _with_meaning_planner_axes(semantic_frame_payload, features=features)
    semantic_frame_payload = _with_relation_priority_resolver_v4(
        semantic_frame_payload,
        raw_text=features.content,
    )
    high_context_trace = _build_high_context_trace(
        raw_text=features.content,
        normalized_text=user_text,
        sense_context=sense_context,
        draft_direct_reason=draft_direct_reason,
        draft_domain=draft_domain,
        draft_frame_detail=draft_frame_detail,
        output_shape=output_shape_label,
        must_preserve=output_shape_must_preserve,
        semantic_frame=semantic_frame_payload,
    )
    return {
        "draft_reply": text,
        "source": "black_phrase_bank_v1",
        "action": draft_action,
        "stance": response_plan.stance,
        "anchor": anchor,
        "must_include": must_include[:5],
        "avoid": list(dict.fromkeys([*STOCK_AVOID, *response_plan.avoid]))[:12],
        "rewrite_rules": _rewrite_rules_for(anchor=anchor, must_include=must_include),
        "sentence_budget": response_plan.sentence_budget,
        "tone": response_plan.tone,
        "followup_policy": response_plan.followup_policy,
        "phrasing_distance": phrasing_plan.distance.value,
        "rewrite_mode": "draft_direct" if draft_direct_reason else "llm_rewrite",
        "direct_surface_reason": draft_direct_reason,
        "output_shape": output_shape_label,
        "draft_domain": draft_domain,
        "draft_frame_detail": draft_frame_detail,
        "semantic_frame": semantic_frame_payload,
        "high_context_trace": high_context_trace,
        "must_preserve": output_shape_must_preserve,
        "banned_fallback": list(OUTPUT_SHAPE_BANNED_FALLBACKS),
    }


_MEANING_PLANNER_FRAME_AXES = (
    "domain",
    "schema",
    "emotion",
    "state_hint",
    "action_hint",
    "draft_frame_family",
    "draft_frame",
    "tone",
    "comparison_focus",
    "relation_type",
    "relation_priority",
)

_RELATION_NONE_LABEL = "__none__"


def _with_meaning_planner_axes(
    semantic_frame: dict[str, object],
    *,
    features: MessageFeatures,
) -> dict[str, object]:
    if not semantic_frame:
        return semantic_frame
    planner_axes = _top_meaning_planner_axes(features)
    if not planner_axes:
        return semantic_frame
    if "comparison_focus" in planner_axes and not _allows_meaning_planner_comparison_focus(
        semantic_frame,
        features=features,
    ):
        planner_axes = dict(planner_axes)
        planner_axes.pop("comparison_focus", None)
        if not planner_axes:
            return semantic_frame

    payload = dict(semantic_frame)
    targets = dict(payload.get("targets") if isinstance(payload.get("targets"), dict) else {})
    target_slots = dict(targets.get("slots") if isinstance(targets.get("slots"), dict) else {})
    payload_slots = dict(payload.get("slots") if isinstance(payload.get("slots"), dict) else {})
    planner_targets = dict(payload.get("planner_targets") if isinstance(payload.get("planner_targets"), dict) else {})
    planner_axis_meta = dict(
        payload.get("planner_axis_meta") if isinstance(payload.get("planner_axis_meta"), dict) else {}
    )
    planner_conflicts = list(
        payload.get("planner_conflicts") if isinstance(payload.get("planner_conflicts"), list) else []
    )

    for axis, axis_payload in planner_axes.items():
        label = str(axis_payload["label"])
        current = str(targets.get(axis) or payload.get(axis) or "").strip()
        if axis in {"relation_type", "relation_priority"} and current == _RELATION_NONE_LABEL:
            current = ""
        planner_targets[axis] = label
        planner_axis_meta[axis] = {
            "confidence": axis_payload["confidence"],
            "source": axis_payload["source"],
        }
        if current and current != label:
            planner_conflicts.append(
                {
                    "axis": axis,
                    "draft": current,
                    "planner": label,
                    "confidence": axis_payload["confidence"],
                    "source": axis_payload["source"],
                }
            )
            continue
        if not current:
            payload[axis] = label
            targets[axis] = label
        if axis == "comparison_focus":
            payload["comparison_focus"] = label
            targets["comparison_focus"] = label
            payload_slots["comparison_focus"] = label
            target_slots["comparison_focus"] = label

    if target_slots:
        targets["slots"] = target_slots
    if payload_slots:
        payload["slots"] = payload_slots
    payload["targets"] = targets
    payload["planner_targets"] = planner_targets
    payload["planner_axis_meta"] = planner_axis_meta
    if planner_conflicts:
        payload["planner_conflicts"] = planner_conflicts

    cues = list(payload.get("pragmatic_cues") if isinstance(payload.get("pragmatic_cues"), list) else [])
    cues.append("meaning_planner_bridge")
    if "comparison_focus" in planner_axes:
        cues.append(str(planner_axes["comparison_focus"]["label"]))
    payload["pragmatic_cues"] = list(dict.fromkeys(cues))

    signals = list(payload.get("signals") if isinstance(payload.get("signals"), list) else [])
    existing_signal_keys = {
        (
            str(signal.get("axis") or ""),
            str(signal.get("label") or ""),
            str(signal.get("source") or ""),
        )
        for signal in signals
        if isinstance(signal, dict)
    }
    for axis, axis_payload in planner_axes.items():
        signal = {
            "axis": axis,
            "label": axis_payload["label"],
            "confidence": axis_payload["confidence"],
            "source": axis_payload["source"],
            "evidence": list(axis_payload["evidence"]),
        }
        signal_key = (str(signal["axis"]), str(signal["label"]), str(signal["source"]))
        if signal_key not in existing_signal_keys:
            signals.append(signal)
            existing_signal_keys.add(signal_key)
    payload["signals"] = signals
    return payload


def _allows_meaning_planner_comparison_focus(
    semantic_frame: dict[str, object],
    *,
    features: MessageFeatures,
) -> bool:
    targets = dict(semantic_frame.get("targets") if isinstance(semantic_frame.get("targets"), dict) else {})
    slots = dict(semantic_frame.get("slots") if isinstance(semantic_frame.get("slots"), dict) else {})
    target_slots = dict(targets.get("slots") if isinstance(targets.get("slots"), dict) else {})
    if semantic_frame.get("comparison_focus") or targets.get("comparison_focus"):
        return True
    if slots.get("comparison_focus") or target_slots.get("comparison_focus"):
        return True
    draft_domain = str(targets.get("domain") or semantic_frame.get("domain") or "")
    draft_frame = str(targets.get("draft_frame") or semantic_frame.get("draft_frame") or "")
    if draft_domain == "money_living" or draft_frame in {"heating_bill_anxiety", "living_cost_pressure"}:
        return True
    raw_text = str(getattr(features, "content", "") or "")
    if _raw_money_comparison_focus(raw_text):
        return True
    signals = _text_signals(raw_text)
    return _money_comparison_focus(signals) is not None


def _top_meaning_planner_axes(features: MessageFeatures) -> dict[str, dict[str, object]]:
    packet = getattr(features, "meaning_packet", None)
    signals = list(getattr(packet, "signals", []) or []) if packet is not None else []
    best: dict[str, dict[str, object]] = {}
    for signal in signals:
        axis = str(getattr(signal, "axis", "") or "").strip()
        if axis not in _MEANING_PLANNER_FRAME_AXES:
            continue
        label = str(getattr(signal, "label", "") or "").strip()
        if not label:
            continue
        confidence = float(getattr(signal, "confidence", 0.0) or 0.0)
        current = best.get(axis)
        if current is not None and float(current["confidence"]) >= confidence:
            continue
        source = str(getattr(signal, "source", "") or "meaning_packet")
        evidence = [str(item) for item in list(getattr(signal, "evidence", []) or []) if str(item)]
        best[axis] = {
            "label": label,
            "confidence": confidence,
            "source": source,
            "evidence": evidence or [f"meaning_axis:{axis}"],
        }
    return best


def _rewrite_rules_for(*, anchor: str, must_include: list[str]) -> list[str]:
    rules = [
        "preserve the draft meaning",
        "only smooth wording, particles, and ending style",
        "do not add new advice, facts, metaphors, or questions",
    ]
    if anchor or must_include:
        rules.append("keep at least one anchor/must_include item")
    return rules


def _shape_result(reply: str, reason: str, *must_preserve: str) -> tuple[str, str, list[str]]:
    return reply, reason, [item for item in must_preserve if item]


def _has_raw_money_comparison_focus_marker(raw_text: str) -> bool:
    raw = str(raw_text or "")
    return any(
        marker in raw
        for marker in (
            "아니라",
            "보다",
            "말고",
            "비교",
            "대신",
            "덜한데",
            "되는데",
            "겠는데",
            "버티겠는데",
            "보여도",
            "처럼 보여도",
            "사실은",
            "실제로는",
            "핵심은",
            "중에",
            "중에서",
            "먼저",
            "이번엔",
            "이번에는",
            "쪽",
            "더",
        )
    )


def _raw_money_comparison_focus(raw_text: str) -> str | None:
    raw = re.sub(r"\s+", "", str(raw_text or ""))
    if not raw:
        return None
    heating_terms = (
        "가스비",
        "도시가스비",
        "난방비",
        "난방",
        "보일러",
        "공과금",
        "고지서",
        "예약난방",
        "온도",
    )
    living_terms = (
        "생활비",
        "식비",
        "식료품",
        "물가",
        "마트",
        "장바구니",
        "장보기",
        "기름값",
        "주유비",
        "식단",
        "영수증",
    )
    specific_living_terms = tuple(term for term in living_terms if term != "생활비")
    if not any(term in raw for term in heating_terms) or not any(term in raw for term in living_terms):
        return None

    def focus_from(fragment: str) -> str | None:
        has_heating = any(term in fragment for term in heating_terms)
        has_living = any(term in fragment for term in living_terms)
        if has_heating and not has_living:
            return "heating"
        if has_living and not has_heating:
            return "living"
        if has_heating and has_living and not any(term in fragment for term in specific_living_terms):
            return "heating"
        return None

    for marker in ("아니라", "보다", "말고", "대신", "덜한데", "되는데", "겠는데", "버티겠는데", "보여도", "같아도"):
        if marker not in raw:
            continue
        focus = focus_from(raw.split(marker, 1)[1])
        if focus is not None:
            return focus
    for marker in ("핵심은", "지금은", "실제로는", "사실은", "실은", "진짜는"):
        if marker not in raw:
            continue
        focus = focus_from(raw.split(marker, 1)[1])
        if focus is not None:
            return focus
    if "쪽으로" in raw:
        focus = focus_from(raw.rsplit("쪽으로", 1)[0][-16:])
        if focus is not None:
            return focus
    if "먼저" in raw:
        focus = focus_from(raw.rsplit("먼저", 1)[0][-16:])
        if focus is not None:
            return focus
    return None


def _with_money_comparison_focus_axis(
    semantic_frame: dict[str, object],
    *,
    raw_text: str,
    sense_context: WordSenseContext | None,
) -> dict[str, object]:
    if not semantic_frame:
        return semantic_frame
    payload = dict(semantic_frame)
    targets = dict(payload.get("targets") if isinstance(payload.get("targets"), dict) else {})
    signals = _text_signals(raw_text, sense_context=sense_context)
    focus = _money_comparison_focus(signals) or _raw_money_comparison_focus(raw_text)
    if focus is None and _is_living_cost_comparison_text(signals):
        focus = "living"
    if focus is None and _is_heating_bill_comparison_text(signals):
        focus = "heating"
    if focus is None and _has_raw_money_comparison_focus_marker(raw_text):
        draft_frame = str(targets.get("draft_frame") or payload.get("draft_frame") or "")
        if draft_frame == "living_cost_pressure":
            focus = "living"
        elif draft_frame == "heating_bill_anxiety":
            focus = "heating"
    if focus is None:
        return semantic_frame
    label = "heating_bill_focus" if focus == "heating" else "living_cost_focus"
    targets["comparison_focus"] = label
    slots = dict(targets.get("slots") if isinstance(targets.get("slots"), dict) else {})
    slots["comparison_focus"] = label
    targets["slots"] = slots
    payload["targets"] = targets
    payload["comparison_focus"] = label
    payload["slots"] = dict(payload.get("slots") if isinstance(payload.get("slots"), dict) else {})
    payload["slots"]["comparison_focus"] = label
    cues = list(payload.get("pragmatic_cues") if isinstance(payload.get("pragmatic_cues"), list) else [])
    payload["pragmatic_cues"] = list(dict.fromkeys([*cues, "money_comparison_focus", label]))
    signals_payload = list(payload.get("signals") if isinstance(payload.get("signals"), list) else [])
    signals_payload.append(
        {
            "axis": "comparison_focus",
            "label": label,
            "confidence": 1.0,
            "source": "draft_money_comparison_focus_v1",
            "evidence": [focus],
        }
    )
    payload["signals"] = signals_payload
    return payload


def _semantic_relation_candidates_for(
    raw_text: str,
    *,
    sense_context: WordSenseContext | None,
    limit: int = 8,
) -> tuple[object, ...]:
    signals = _text_signals(raw_text, sense_context=sense_context)
    resolved_senses = resolve_word_senses(signals, context=sense_context)
    semantic_tags = infer_semantic_tags(signals, context=sense_context)
    return rank_semantic_relations(
        infer_semantic_relations(
            signals,
            base_tags=semantic_tags,
            resolved_senses=resolved_senses,
        )
    )[:limit]


def _semantic_relation_candidate_payload(relation: object) -> dict[str, object]:
    return {
        "name": str(getattr(relation, "name", "") or ""),
        "relation_type": str(getattr(relation, "name", "") or ""),
        "relation_priority": str(getattr(relation, "priority", "") or ""),
        "priority": str(getattr(relation, "priority", "") or ""),
        "priority_rank": int(getattr(relation, "priority_rank", 99) or 99),
        "score": float(getattr(relation, "score", 0.0) or 0.0),
        "confidence": float(getattr(relation, "confidence", 0.0) or 0.0),
        "tags": list(getattr(relation, "tags", ()) or ()),
        "matched_tags": list(getattr(relation, "matched_tags", ()) or ()),
        "matched_senses": list(getattr(relation, "matched_senses", ()) or ()),
        "matched_cues": list(getattr(relation, "matched_cues", ()) or ()),
        "positive_evidence": list(getattr(relation, "positive_evidence", ()) or ()),
        "negative_evidence": list(getattr(relation, "negative_evidence", ()) or ()),
        "source": "draft_semantic_relation_candidates_v1",
    }


def _none_semantic_relation_payload() -> dict[str, object]:
    return {
        "name": _RELATION_NONE_LABEL,
        "relation_type": _RELATION_NONE_LABEL,
        "relation_priority": _RELATION_NONE_LABEL,
        "priority": _RELATION_NONE_LABEL,
        "priority_rank": 99,
        "score": 0.0,
        "confidence": 1.0,
        "tags": [],
        "matched_tags": [],
        "matched_senses": [],
        "matched_cues": [],
        "positive_evidence": ["no_relation_candidate"],
        "negative_evidence": [],
        "source": "draft_semantic_relation_candidates_v1",
    }


def _with_semantic_relation_candidate_axes(
    semantic_frame: dict[str, object],
    *,
    raw_text: str,
    sense_context: WordSenseContext | None,
) -> dict[str, object]:
    if not semantic_frame:
        return semantic_frame

    candidates = [
        _semantic_relation_candidate_payload(relation)
        for relation in _semantic_relation_candidates_for(
            raw_text,
            sense_context=sense_context,
            limit=8,
        )
    ]
    selected = candidates[0] if candidates else _none_semantic_relation_payload()
    relation_type = str(selected.get("relation_type") or _RELATION_NONE_LABEL)
    relation_priority = str(selected.get("relation_priority") or _RELATION_NONE_LABEL)
    confidence = float(selected.get("confidence") or 0.0)

    payload = dict(semantic_frame)
    targets = dict(payload.get("targets") if isinstance(payload.get("targets"), dict) else {})
    target_slots = dict(targets.get("slots") if isinstance(targets.get("slots"), dict) else {})
    payload_slots = dict(payload.get("slots") if isinstance(payload.get("slots"), dict) else {})
    targets["relation_type"] = relation_type
    targets["relation_priority"] = relation_priority
    target_slots["relation_type"] = relation_type
    target_slots["relation_priority"] = relation_priority
    targets["slots"] = target_slots

    payload["relation_type"] = relation_type
    payload["relation_priority"] = relation_priority
    payload["selected_relation"] = selected
    payload["relation_candidates"] = candidates
    payload_slots["relation_type"] = relation_type
    payload_slots["relation_priority"] = relation_priority
    payload["slots"] = payload_slots
    payload["targets"] = targets

    cues = list(payload.get("pragmatic_cues") if isinstance(payload.get("pragmatic_cues"), list) else [])
    cues.append("semantic_relation_candidates")
    cues.append(f"relation_type:{relation_type}")
    if relation_priority != _RELATION_NONE_LABEL:
        cues.append(f"relation_priority:{relation_priority}")
    payload["pragmatic_cues"] = list(dict.fromkeys(cues))

    evidence = list(selected.get("positive_evidence") if isinstance(selected.get("positive_evidence"), list) else [])
    if not evidence:
        evidence = [relation_type]
    signals_payload = list(payload.get("signals") if isinstance(payload.get("signals"), list) else [])
    signals_payload.extend(
        [
            {
                "axis": "relation_type",
                "label": relation_type,
                "confidence": confidence,
                "source": "draft_semantic_relation_candidates_v1",
                "evidence": evidence,
            },
            {
                "axis": "relation_priority",
                "label": relation_priority,
                "confidence": confidence,
                "source": "draft_semantic_relation_candidates_v1",
                "evidence": evidence,
            },
        ]
    )
    payload["signals"] = signals_payload
    return payload


def _with_relation_priority_resolver_v4(
    semantic_frame: dict[str, object],
    *,
    raw_text: str,
) -> dict[str, object]:
    if not semantic_frame:
        return semantic_frame
    return draft_relation_priority_resolver_v4.apply_relation_priority_resolution(
        dict(semantic_frame),
        raw_text=raw_text,
    )


def _build_high_context_trace(
    *,
    raw_text: str,
    normalized_text: str,
    sense_context: WordSenseContext | None,
    draft_direct_reason: str,
    draft_domain: str,
    draft_frame_detail: str,
    output_shape: str,
    must_preserve: list[str],
    semantic_frame: dict[str, object],
) -> dict[str, object]:
    signals = _text_signals(raw_text, sense_context=sense_context)
    resolved_senses = resolve_word_senses(signals, context=sense_context)
    sense_tags = tuple(
        dict.fromkeys(
            tag
            for sense in resolved_senses
            for tag in sense.tags
        )
    )
    semantic_tags = infer_semantic_tags(signals, context=sense_context)
    semantic_relations = infer_semantic_relations(
        signals,
        base_tags=semantic_tags,
        resolved_senses=resolved_senses,
    )
    semantic_candidates = rank_semantic_candidates(
        signals,
        context=sense_context,
        limit=8,
    )
    return {
        "layers": [
            "raw_text",
            "normalized_text",
            "compact_text",
            "token_candidates",
            "token_ngrams",
            "surface_markers",
            "resolved_word_senses",
            "sense_tags",
            "semantic_tags",
            "semantic_relations",
            "semantic_word_candidates",
            "salience_profile",
            "context_pressure_profile",
            "semantic_frame",
            "draft_event_frame",
        ],
        "raw_text": _compact(raw_text, 240),
        "normalized_text": _compact(normalized_text, 240),
        "compact_text": signals.compact[:240],
        "token_candidates": list(signals.words[:32]),
        "token_ngrams": list(signals.token_ngrams[:48]),
        "surface_markers": _surface_markers(raw_text),
        "resolved_word_senses": [
            {
                "word": sense.word,
                "sense": sense.sense,
                "score": round(sense.score, 3),
                "tags": list(sense.tags),
                "matched_cues": list(sense.matched_cues),
            }
            for sense in resolved_senses[:12]
        ],
        "sense_tags": list(sense_tags[:24]),
        "semantic_tags": list(semantic_tags[:40]),
        "semantic_relations": [
            {
                "name": relation.name,
                "priority": relation.priority,
                "priority_rank": relation.priority_rank,
                "score": relation.score,
                "confidence": relation.confidence,
                "tags": list(relation.tags),
                "matched_tags": list(relation.matched_tags),
                "matched_senses": list(relation.matched_senses),
                "matched_cues": list(relation.matched_cues),
                "blocked_cues": list(relation.blocked_cues),
                "positive_evidence": list(relation.positive_evidence),
                "negative_evidence": list(relation.negative_evidence),
            }
            for relation in rank_semantic_relations(semantic_relations)[:8]
        ],
        "semantic_word_candidates": [
            {
                "value": candidate.value,
                "score": round(candidate.score, 3),
                "matched_tags": list(candidate.matched_tags),
                "candidate_tags": list(candidate.candidate_tags),
                "matched_aliases": list(candidate.matched_aliases),
                "context_gate": candidate.context_gate,
            }
            for candidate in semantic_candidates[:8]
        ],
        "salience_profile": _salience_profile(
            signals=signals,
            semantic_tags=semantic_tags,
            sense_tags=sense_tags,
            semantic_candidates=semantic_candidates,
            must_preserve=must_preserve,
        ),
        "context_pressure_profile": _context_pressure_profile(
            signals=signals,
            semantic_tags=semantic_tags,
            sense_tags=sense_tags,
            surface_markers=tuple(_surface_markers(raw_text)["markers"]),
        ),
        "semantic_frame": dict(semantic_frame),
        "context": {
            "raw_texts": list(sense_context.raw_texts[-3:]) if sense_context else [],
            "compact_text": sense_context.compact[-240:] if sense_context else "",
            "tags": list(sense_context.tags) if sense_context else [],
        },
        "draft_event_frame": {
            "direct_surface_reason": draft_direct_reason,
            "draft_domain": draft_domain,
            "draft_frame_detail": draft_frame_detail,
            "output_shape": output_shape,
            "must_preserve": list(must_preserve),
            "semantic_frame": dict(semantic_frame),
        },
    }


def _context_pressure_profile(
    *,
    signals: TextSignals,
    semantic_tags: tuple[str, ...],
    sense_tags: tuple[str, ...],
    surface_markers: tuple[str, ...],
) -> dict[str, object]:
    compact = signals.compact
    tags = {*semantic_tags, *sense_tags}
    markers: list[str] = []
    must_acknowledge: list[str] = []

    def add(marker: str, ack: str) -> None:
        if marker not in markers:
            markers.append(marker)
        if ack and ack not in must_acknowledge:
            must_acknowledge.append(ack)

    if _has_any(
        compact,
        "나만그런",
        "나만이래",
        "이거나만",
        "나만느끼",
        "나만신경",
        "나만불편",
    ):
        add("self_doubt_validation", "나만 그런 게 아니라는 확인")
    if _has_any(
        compact,
        "괜히신경",
        "하루종일신경",
        "계속신경",
        "신경쓰여",
        "신경쓰인",
        "찝찝",
        "찜찜",
        "꺼림칙",
        "마음에걸",
        "묘하게걸",
    ) or tags & {"uneasy"}:
        add("lingering_unease", "계속 신경 쓰이는 찝찝함")
    if _has_any(
        compact,
        "말하기애매",
        "말꺼내기애매",
        "화내기도애매",
        "따지기도애매",
        "괜히예민",
        "예민한사람",
        "괜히유난",
        "유난떠는",
        "분위기이상",
    ):
        add("low_voice_boundary", "말하기 애매한 부담")
    if (
        _has_any(compact, "그냥참", "참고있", "참는중", "넘기고있", "모른척", "괜찮은척")
        and not _has_any(compact, "그냥참고자", "참고자")
    ):
        add("passive_containment", "참고 넘기는 압력")
    if _has_any(
        compact,
        "눈치",
        "바빠보",
        "말걸기애매",
        "직원분",
        "종업원",
        "민폐",
        "어색",
        "부담줄까",
        "불편하게할까",
    ):
        add("social_face_pressure", "상대 눈치와 분위기 부담")
    if _has_any(
        compact,
        "애매",
        "고민",
        "어쩔까",
        "모르겠",
        "반반",
        "갈지말지",
        "살까말까",
        "먹을까말까",
        "할까말까",
        "챙길지",
    ) or tags & {"decision", "choice", "uncertain"}:
        add("decision_ambivalence", "선택을 미루게 하는 애매함")

    if "self_doubt_validation" in markers:
        response_mode = "validate_first"
    elif "low_voice_boundary" in markers or "passive_containment" in markers:
        response_mode = "low_voice_boundary"
    elif "lingering_unease" in markers:
        response_mode = "name_unease"
    elif "social_face_pressure" in markers:
        response_mode = "social_tact"
    elif "decision_ambivalence" in markers:
        response_mode = "choose_practical"
    elif "request_signal" in surface_markers:
        response_mode = "answer_directly"
    else:
        response_mode = "neutral"

    tone_level = _context_pressure_tone_level(
        compact=compact,
        surface_markers=surface_markers,
    )

    return {
        "markers": markers,
        "response_mode": response_mode,
        "tone_level": tone_level,
        "must_acknowledge": must_acknowledge,
        "surface_markers": list(surface_markers),
    }


def _context_pressure_tone_level(
    *,
    compact: str,
    surface_markers: tuple[str, ...],
) -> str:
    markers = set(surface_markers)
    hot_terms = (
        "진짜",
        "너무",
        "완전",
        "개빡",
        "빡쳐",
        "빡침",
        "짜증",
        "열받",
        "미치겠",
        "답답",
        "살려",
        "최악",
        "킹받",
        "나락",
        "멘탈",
    )
    soft_terms = (
        "속상",
        "우울",
        "힘들",
        "지쳐",
        "외롭",
        "무기력",
        "눈물",
        "서운",
        "불안",
        "무섭",
    )
    low_terms = (
        "생각많",
        "잠안오",
        "새벽",
        "밤마다",
        "조용히",
        "괜히",
        "묘하게",
    )
    if "laughter" in markers and ("slang_intensity" in markers or _has_any(compact, *hot_terms)):
        return "heated_playful"
    if "laughter" in markers:
        return "playful"
    if "soft_tear" in markers or _has_any(compact, *soft_terms):
        return "soft"
    if "slang_intensity" in markers or "emphasis_mark" in markers or _has_any(compact, *hot_terms):
        return "hot"
    if "late_night_signal" in markers or _has_any(compact, *low_terms):
        return "low"
    return "neutral"


def _apply_context_pressure_tone(reply: str, *, mode: str, tone_level: str) -> str:
    suffix = ""
    if tone_level == "heated_playful":
        suffix = "웃으면서 말해도 속은 꽤 긁힌 상태라, 여기서 한 번 끊어주는 게 좋아."
    elif tone_level == "playful":
        suffix = "장난처럼 ㅋㅋ 붙여도 그냥 넘기기엔 은근히 걸리는 포인트야."
    elif tone_level == "hot":
        if mode in {"low_voice_boundary", "social_tact"}:
            suffix = "지금 바로 세게 나가고 싶어도, 짧게 끊는 게 더 세게 먹혀."
        elif mode == "choose_practical":
            suffix = "오래 끌수록 더 답답해지니까 작게 끊자."
        else:
            suffix = "그 정도면 네가 과한 게 아니라 신호가 꽤 큰 편이야."
    elif tone_level == "soft":
        suffix = "일단 네 마음부터 덜 다치게 가자."
    elif tone_level == "low":
        suffix = "지금은 크게 결론 내기보다 잠깐 내려놓는 쪽이 나아."
    if not suffix:
        return reply
    if suffix in reply:
        return reply
    base = reply.rstrip()
    tail = suffix.rstrip(". ")
    if base.endswith("."):
        return f"{base[:-1]}, {tail}."
    return f"{base} {tail}."


def _salience_profile(
    *,
    signals: TextSignals,
    semantic_tags: tuple[str, ...],
    sense_tags: tuple[str, ...],
    semantic_candidates: tuple[object, ...],
    must_preserve: list[str],
) -> dict[str, object]:
    compact = signals.compact
    all_tags = {*semantic_tags, *sense_tags, *_salience_candidate_tags(semantic_candidates)}
    emotion_tags = _salience_emotion_tags(compact, all_tags)
    topic_clusters = _salience_topic_clusters(all_tags)
    surface_markers = _surface_markers(signals.raw)["markers"]
    temperature = _salience_temperature(compact, emotion_tags, tuple(str(marker) for marker in surface_markers))
    reaction_mode = _salience_reaction_mode(
        emotion_tags=emotion_tags,
        topic_clusters=topic_clusters,
        surface_markers=tuple(str(marker) for marker in surface_markers),
    )
    dominant_context = _salience_dominant_context(
        topic_clusters=topic_clusters,
        semantic_candidates=semantic_candidates,
    )
    return {
        "temperature": temperature,
        "emotion_tags": emotion_tags,
        "topic_clusters": topic_clusters,
        "dominant_context": dominant_context,
        "reaction_mode": reaction_mode,
        "semantic_labels": [
            getattr(candidate, "value", "")
            for candidate in semantic_candidates[:5]
            if getattr(candidate, "value", "")
        ],
        "must_keep_surface_terms": _salience_surface_terms(
            signals=signals,
            must_preserve=must_preserve,
            semantic_candidates=semantic_candidates,
        ),
    }


def _salience_candidate_tags(semantic_candidates: tuple[object, ...]) -> set[str]:
    tags: set[str] = set()
    for candidate in semantic_candidates[:5]:
        if not _salience_candidate_is_contextual(candidate):
            continue
        for tag in _salience_candidate_tag_values(candidate):
            if tag:
                tags.add(tag)
    return tags


def _salience_candidate_is_contextual(candidate: object) -> bool:
    accepted_gates = {"accepted", "specific_tag_only"}
    try:
        score = float(getattr(candidate, "score", 0.0))
    except (TypeError, ValueError):
        score = 0.0
    if score < 3.0:
        return False
    if str(getattr(candidate, "context_gate", "accepted")) not in accepted_gates:
        return False
    matched_aliases = tuple(getattr(candidate, "matched_aliases", ()))
    if len(matched_aliases) < 2 and score < 6.0:
        return False
    candidate_tag_values = _salience_candidate_tag_values(candidate)
    if {"short_word", "ambiguous"} <= candidate_tag_values:
        return False
    return True


def _salience_candidate_tag_values(candidate: object) -> set[str]:
    return {
        str(tag)
        for tag in getattr(candidate, "candidate_tags", ())
        if tag
    }


def _salience_emotion_tags(compact: str, tags: set[str]) -> list[str]:
    emotions: list[str] = []

    def add(tag: str) -> None:
        if tag not in emotions:
            emotions.append(tag)

    if tags & {"frustration", "annoyance", "bad_luck"} or _has_any(
        compact, "킹받", "빡", "짜증", "답답", "에바", "선넘", "나락", "억까"
    ):
        add("frustration")
    if tags & {"panic", "fear", "nervous"} or _has_any(compact, "멘붕", "식은땀", "심장", "무서", "쫄"):
        add("panic")
    if tags & {"positive", "happy", "satisfaction", "joy", "lucky"} or _has_any(
        compact, "대만족", "개꿀", "좋더라", "짜릿", "극락", "힐링"
    ):
        add("positive_lift")
    if tags & {"fatigue", "low_energy", "sleepy"} or _has_any(
        compact, "피곤", "졸려", "기빨", "무기력", "잠이안오", "잠안오", "잠이안온"
    ):
        add("fatigue")
    if tags & {"sad", "hurt", "bittersweet", "regret"} or _has_any(compact, "서운", "속상", "씁쓸", "후회"):
        add("soft_hurt")
    if tags & {"reflective", "self_reflection", "life", "philosophy"} or _has_any(
        compact, "인생", "가치관", "묘비명", "후회", "현타"
    ):
        add("reflective")
    if tags & {"detail", "analysis", "analytical", "obsession"} or _has_any(
        compact, "디테일", "1단위", "칼같", "완벽", "과몰입", "장인정신"
    ):
        add("detail_focus")
    if tags & {"decision", "choice", "uncertain"} or _has_any(compact, "고민", "골라", "추천", "뭐먹", "어떡"):
        add("decision_pressure")
    if not emotions:
        add("neutral_observation")
    return emotions


