def _salience_topic_clusters(tags: set[str]) -> list[str]:
    clusters = [name for name, group_tags in _SALIENCE_TOPIC_GROUPS if tags & group_tags]
    return clusters[:8]


def _salience_dominant_context(
    *,
    topic_clusters: list[str],
    semantic_candidates: tuple[object, ...],
) -> dict[str, object]:
    candidate = _salience_dominant_candidate(semantic_candidates)
    cluster = ""
    label = ""
    score = 0.0
    if candidate is not None:
        candidate_tags = _salience_candidate_tag_values(candidate)
        cluster = _salience_cluster_for_tags(candidate_tags, topic_clusters)
        label = str(getattr(candidate, "value", "") or "")
        if "ai_build_pipeline" in topic_clusters and _has_any(
            _normalize(label),
            "브이램",
            "vram",
            "양자화",
            "프롬프트",
            "로컬봇",
            "로컬서버",
        ):
            cluster = "ai_build_pipeline"
        try:
            score = float(getattr(candidate, "score", 0.0))
        except (TypeError, ValueError):
            score = 0.0
    if not cluster:
        cluster = topic_clusters[0] if topic_clusters else "general"
    return {
        "cluster": cluster,
        "label": label,
        "candidate_score": round(score, 3),
        "supporting_clusters": [
            topic_cluster
            for topic_cluster in topic_clusters
            if topic_cluster != cluster
        ],
    }


def _salience_dominant_candidate(semantic_candidates: tuple[object, ...]) -> object | None:
    for candidate in semantic_candidates[:5]:
        if _salience_candidate_is_contextual(candidate):
            return candidate
    return None


def _salience_cluster_for_tags(candidate_tags: set[str], topic_clusters: list[str]) -> str:
    # High-context micro tags are intentionally routed before broad topic clusters.
    if "ai_build_pipeline" in topic_clusters and candidate_tags & {
        "draft_frame",
        "template",
        "nlg",
        "response_style",
        "persona",
        "dry_tone",
    }:
        return "ai_build_pipeline"
    if candidate_tags & {
        "life_admin",
        "verification",
        "sms",
        "maintenance_time",
        "calendar",
        "alert_fail",
        "parcel_locker",
        "package_missing",
        "door_code",
        "subscription_cancel",
        "health_checkup",
        "cancellation_fee",
    } or (
        "admin" in candidate_tags
        and candidate_tags & {"reservation", "hospital", "documents", "public_office"}
    ):
        return "life_admin_detail"
    if candidate_tags & {"laundry", "bedding"} and candidate_tags & {"cleaning", "satisfaction", "relief"}:
        return "home_daily_detail"
    if "food_waste" in candidate_tags and candidate_tags & {"smell", "trash_bag"}:
        return "home_daily_detail"
    if candidate_tags & {
        "home_maintenance",
        "dryer",
        "lint",
        "recycling",
        "trash_bag",
        "food_waste",
        "drain",
        "hair",
        "toilet_paper",
        "heating",
        "boiler",
        "electric_blanket",
        "fridge",
        "spoiled_food",
        "expired_food",
        "milk",
        "sink",
        "drain_clog",
        "fluorescent",
        "flicker",
        "gas_stove",
        "lost_card",
        "wet_umbrella",
    } or ("laundry" in candidate_tags and candidate_tags & {"chores", "procrastination", "home"}):
        return "home_maintenance_detail"
    if candidate_tags & {"taxi"} and candidate_tags & {"smalltalk", "driver", "social_battery", "fatigue"}:
        return "relationship_social"
    if candidate_tags & {
        "payment",
        "card_decline",
        "limit",
        "transfer_mistake",
        "transit_card",
        "balance_low",
        "taxi",
        "missed_bus",
        "maintenance_fee",
        "bills",
        "bill",
        "coupon",
        "expiration",
        "one_plus_one",
        "stamp",
        "fee",
    }:
        return "payment_errand"
    if candidate_tags & {"exit", "wrong_exit"} and candidate_tags & {"subway", "transit", "commute", "navigation"}:
        return "transit_micro_fail"
    if candidate_tags & {
        "device_fail",
        "map_app",
        "navigation",
        "wrong_route",
        "spreadsheet",
        "unsaved",
        "zoom",
        "mic",
        "ink_empty",
        "cable_damage",
        "router",
        "tiny_text",
    }:
        return "device_small_fail"
    if candidate_tags & {"medicine", "cold_medicine", "drowsy"}:
        return "body_health"
    if candidate_tags & {"sales_pitch", "insurance"}:
        return "relationship_social"
    if "relationship_social" in topic_clusters and candidate_tags & {
        "imposter_syndrome",
        "sound_drain",
        "social_battery",
    }:
        return "relationship_social"
    if "social_mask_survival" in topic_clusters and {"work", "recognition", "small_comfort"} <= candidate_tags:
        return "social_mask_survival"
    if "commute_work" in topic_clusters and (
        "overtime" in candidate_tags
        or (
            "last_minute" in candidate_tags
            and "office" in candidate_tags
            and not candidate_tags & {"social_mask", "boss", "hidden_scope", "bomb"}
        )
        or {"intrusive_thought", "task"} <= candidate_tags
    ):
        return "commute_work"
    if "relationship_social" in topic_clusters and candidate_tags & {
        "praise_need",
        "celebration",
        "unasked",
    }:
        return "relationship_social"
    if "relationship_social" in topic_clusters and candidate_tags & {"ordinary_care", "small_comfort"} and "work" not in candidate_tags:
        return "relationship_social"
    if "money_spending" in topic_clusters and "shopping" in candidate_tags and candidate_tags & {
        "package",
        "delivery",
        "anticipation",
        "pre_opening",
        "expectation_drop",
    }:
        return "money_spending"
    if "weather_daily" in topic_clusters and candidate_tags & {"wet_shoes", "socks", "discomfort"}:
        return "weather_daily"
    if "life_reflection" in topic_clusters and candidate_tags & {"rest_pressure", "anticipation_anxiety", "free_time"}:
        return "life_reflection"
    if "chat_social_misfire" in topic_clusters and candidate_tags & {
        "text_self_censor",
        "message_delete",
    }:
        return "chat_social_misfire"
    if candidate_tags & {"friday", "mute", "rest_boundary"}:
        return "chat_social_misfire"
    if "social_mask_survival" in topic_clusters and candidate_tags & {
        "late_comeback",
        "overapologizing",
        "petty_guilt",
        "pantry",
    }:
        return "social_mask_survival"
    if candidate_tags & {"doorbell", "white_noise"}:
        return "home_daily_detail"
    if "stealth" in candidate_tags and candidate_tags & {"delivery", "package", "home"}:
        return "home_daily_detail"
    if "movement" in candidate_tags and candidate_tags & {"delivery", "low_energy"}:
        return "home_daily_detail"
    if "transit_micro_fail" in topic_clusters and candidate_tags & {
        "commute",
        "transit",
        "bus",
        "subway",
        "crowd",
        "heat",
    } and not (candidate_tags & {"embarrassment", "fashion", "clothes", "button"}):
        return "transit_micro_fail"
    if "weather_daily" in topic_clusters and candidate_tags & {
        "dust",
        "throat",
        "mask",
        "outfit",
        "unpredictable",
    }:
        return "weather_daily"
    if "scenery_mood" in topic_clusters and candidate_tags & {
        "fresh_air",
        "rain_after",
        "sunset",
        "photo",
    }:
        return "scenery_mood"
