def _salience_temperature(compact: str, emotion_tags: list[str], surface_markers: tuple[str, ...]) -> str:
    if "frustration" in emotion_tags or "panic" in emotion_tags or "slang_intensity" in surface_markers:
        return "hot"
    if "positive_lift" in emotion_tags:
        return "warm"
    if "soft_hurt" in emotion_tags or "fatigue" in emotion_tags or "reflective" in emotion_tags:
        return "soft"
    if _has_any(compact, "ㅋㅋ", "ㅎㅎ"):
        return "playful"
    return "neutral"


def _salience_reaction_mode(
    *,
    emotion_tags: list[str],
    topic_clusters: list[str],
    surface_markers: tuple[str, ...],
) -> str:
    if "request_signal" in surface_markers or "decision_pressure" in emotion_tags:
        return "pick_or_advise"
    if "frustration" in emotion_tags or "panic" in emotion_tags:
        return "react_first"
    if "soft_hurt" in emotion_tags or "fatigue" in emotion_tags:
        return "comfort_first"
    if "detail_focus" in emotion_tags:
        return "mirror_detail"
    if "life_reflection" in topic_clusters or "reflective" in emotion_tags:
        return "reflect_with_position"
    if "positive_lift" in emotion_tags:
        return "amplify"
    return "continue"


def _salience_surface_terms(
    *,
    signals: TextSignals,
    must_preserve: list[str],
    semantic_candidates: tuple[object, ...],
) -> list[str]:
    stopwords = {
        "오늘",
        "진짜",
        "그냥",
        "너무",
        "완전",
        "약간",
        "요즘",
        "이번",
        "저번",
        "내가",
        "나는",
        "근데",
        "아니",
        "해서",
        "하면",
        "같아",
        "같음",
        "있는",
        "없는",
        "뭐",
    }
    terms: list[str] = []

    def add(term: str) -> None:
        cleaned = _compact(term, 40)
        if cleaned and cleaned not in terms:
            terms.append(cleaned)

    for term in must_preserve:
        add(term)
    for candidate in semantic_candidates[:5]:
        for alias in getattr(candidate, "matched_aliases", ())[:3]:
            add(str(alias))
        add(str(getattr(candidate, "value", "")))
    for word in signals.words:
        if len(word) < 2 or word in stopwords:
            continue
        add(word)
        if len(terms) >= 18:
            break
    return terms[:18]


def _surface_markers(raw_text: str) -> dict[str, object]:
    raw = str(raw_text or "")
    compact = _normalize(raw)
    markers: list[str] = []
    if "?" in raw:
        markers.append("question_mark")
    if "!" in raw:
        markers.append("emphasis_mark")
    if "," in raw or "，" in raw:
        markers.append("comma_pause")
    if "..." in raw or "…" in raw:
        markers.append("trailing_pause")
    if "ㅋㅋ" in raw or "ㅎㅎ" in raw:
        markers.append("laughter")
    if "ㅠ" in raw or "ㅜ" in raw:
        markers.append("soft_tear")
    if re.search(r"(^|\s)야[,!?\s]", raw):
        markers.append("direct_call")
    if _has_any(compact, "킹받", "개웃", "개빡", "미쳤", "나락", "현타"):
        markers.append("slang_intensity")
    if _has_any(compact, "자냐", "잠안오", "새벽", "밤"):
        markers.append("late_night_signal")
    if _has_any(compact, "뭐먹", "배고", "점심", "저녁", "야식"):
        markers.append("food_decision_signal")
    if _has_any(compact, "어떡", "어쩌", "추천", "골라", "뭐할"):
        markers.append("request_signal")
    return {
        "markers": markers,
        "question_mark_count": raw.count("?"),
        "exclamation_count": raw.count("!"),
        "comma_count": raw.count(",") + raw.count("，"),
        "raw_length": len(raw),
        "compact_length": len(compact),
    }


def _stable_variant(source: str, variants: tuple[str, ...], *, salt: str = "") -> str:
    if not variants:
        return ""
    normalized = _normalize(f"{salt}:{source}")
    index = sum(ord(char) for char in normalized) % len(variants)
    return variants[index]


def _choose_keyword_slot(
    signals: TextSignals,
    choices: tuple[tuple[tuple[str, ...], str], ...],
    default: str,
) -> str:
    for needles, value in choices:
        if signals.has_any_compact(*needles):
            return value
    return default


def _assemble_classified_slot_reply(
    signals: TextSignals,
    *,
    detail: str,
    templates: tuple[str, ...],
    fixed_slots: dict[str, str] | None = None,
    keyword_slots: dict[str, tuple[tuple[tuple[tuple[str, ...], str], ...], str]] | None = None,
    variant_slots: dict[str, tuple[str, ...]] | None = None,
) -> str:
    selection = _DRAFT_SLOT_SELECTOR.select(
        signals,
        detail=detail,
        slot_bank={
            "fixed_slots": fixed_slots or {},
            "keyword_slots": keyword_slots or {},
            "variant_slots": variant_slots or {},
            "templates": templates,
        },
    )
    return selection.render()


_DRAFT_SLOT_SELECTOR = RuleDraftSlotSelector()


def set_draft_slot_selector(selector: DraftSlotSelector) -> None:
    global _DRAFT_SLOT_SELECTOR
    _DRAFT_SLOT_SELECTOR = selector


def _slot_bank_selection(signals: TextSignals, detail: str) -> DraftSlotSelection:
    slot_bank = DRAFT_SLOT_BANKS[detail]
    return _DRAFT_SLOT_SELECTOR.select(
        signals,
        detail=detail,
        slot_bank=slot_bank,
    )


def _slot_bank_reply(signals: TextSignals, detail: str) -> str:
    return _slot_bank_selection(signals, detail).render()


def _render_semantic_word_bank_reply(signals: TextSignals) -> tuple[str, str, list[str]] | None:
    if signals.has_any_compact("족보", "가계도", "조상", "할아버지", "할머니", "집안내력") and signals.has_any_compact(
        "팔만대장경",
        "대장경",
        "팔만",
        "끝도없",
        "너무길",
        "모두의할아버지",
        "복잡",
    ):
        selection = _slot_bank_selection(signals, "semantic_comic_exaggeration_record")
        return _shape_result(
            selection.render(),
            "korean_daily_semantic_comic_exaggeration_record",
            selection.slots.get("topic", "족보"),
            selection.slots.get("metaphor", "팔만대장경급"),
        )
    return None


