def _sense_has_context_only_evidence(matched_cues: tuple[str, ...]) -> bool:
    return bool(matched_cues) and all(
        cue.startswith("context:") or cue.startswith("context_phrase:")
        for cue in matched_cues
    )


def _sense_has_current_turn_detail_evidence(matched_cues: tuple[str, ...]) -> bool:
    return bool(matched_cues) and any(
        not (cue.startswith("context:") or cue.startswith("context_phrase:"))
        for cue in matched_cues
    )


