def _has_priority_daily_reply_before_current_word_sense(signals: TextSignals) -> bool:
    """Current-turn word sense is a fallback, not a replacement for known frames."""

    priority_renderers = (
        _render_korean_daily_micro_context_override_reply,
        _render_korean_daily_specialized_transit_commute_reply,
        _render_korean_daily_specialized_home_repair_maintenance_reply,
        _render_korean_daily_specialized_sports_fan_reply,
        _render_korean_daily_specialized_performance_culture_reply,
        _render_korean_daily_specialized_outing_belongings_reply,
        _render_korean_daily_specialized_digital_work_device_reply,
        _render_korean_daily_specialized_food_service_reply,
        _render_korean_daily_specialized_retail_store_reply,
        _render_korean_daily_specialized_body_health_sleep_workout_reply,
        _render_korean_daily_specialized_payment_transport_cleaning_weather_errand_reply,
        _render_korean_daily_specialized_beauty_laundry_study_family_home_reply,
        _render_korean_daily_specialized_plants_kitchen_admin_body_local_reply,
        _render_korean_daily_foundation_life_admin_reply,
        _render_korean_daily_specialized_real_life_reply,
    )
    for renderer in priority_renderers:
        if renderer(signals) is not None:
            return True
    return False


def _contextual_detail_from_word_senses(
    signals: TextSignals,
    *,
    evidence: str,
) -> str | None:
    resolved = resolve_word_senses(signals, context=signals.sense_context)
    for sense_name, detail in _CONTEXTUAL_WORD_SENSE_DETAILS:
        for sense in resolved:
            if sense.sense != sense_name:
                continue
            if evidence == "context" and _sense_has_context_only_evidence(sense.matched_cues):
                return detail
            if (
                evidence == "current"
                and _allow_current_contextual_word_detail(signals, detail)
                and _sense_has_current_turn_detail_evidence(sense.matched_cues)
            ):
                return detail
    return None


def _infer_mixed_topic_draft_frame_detail(user_text: str) -> str | None:
    profile = infer_mixed_topic_profile(
        user_text,
        is_question="?" in str(user_text or ""),
    )
    if profile is None:
        return None
    return profile.draft_frame


def _infer_contextual_draft_frame_detail(
    user_text: str,
    *,
    sense_context: WordSenseContext | None = None,
) -> str | None:
    if sense_context is not None:
        choice_detail = _infer_contextual_choice_draft_frame_detail(
            user_text,
            sense_context=sense_context,
        )
        if choice_detail:
            return choice_detail
        discourse_detail = _infer_contextual_discourse_draft_frame_detail(
            user_text,
            sense_context=sense_context,
        )
        if discourse_detail:
            return discourse_detail
        reference_detail = _infer_contextual_reference_draft_frame_detail(
            user_text,
            sense_context=sense_context,
        )
        if reference_detail:
            return reference_detail
    signals = _text_signals(user_text, sense_context=sense_context)
    if sense_context is not None:
        context_detail = _contextual_detail_from_word_senses(signals, evidence="context")
        if context_detail:
            return context_detail
    return None


def _infer_current_word_sense_draft_frame_detail(
    user_text: str,
    *,
    sense_context: WordSenseContext | None = None,
) -> str | None:
    signals = _text_signals(user_text, sense_context=sense_context)
    if _has_priority_daily_reply_before_current_word_sense(signals):
        return None
    return _contextual_detail_from_word_senses(signals, evidence="current")


