def _render_korean_knowledge_reflection_reply(*, raw: str, text: str) -> tuple[str, str, list[str]] | None:
    if not text:
        return None

    serious_markers = (
        "왜",
        "어디까지",
        "정당",
        "동의",
        "볼수",
        "생각해",
        "같은사람",
        "해야할까",
        "해야",
        "따라야",
        "반영",
        "도움",
        "해가",
        "책임",
        "의미",
        "영향",
        "흔적",
        "반복",
        "공정",
        "정의",
        "중립적",
        "될까",
        "가능할까",
        "있을까",
        "가까울까",
        "뭘까",
        "남길까",
        "나을",
        "나쁠까",
        "만들까",
        "현명",
        "갈등",
        "가치",
        "관습",
        "좋은사회",
        "돈으로행복",
        "행복을살",
        "더행복",
        "뭐라고봐",
        "차이",
        "할까",
        "일까",
        "을까",
        "걸까",
        "질까",
        "클까",
        "맞을까",
        "뭐야",
        "봐",
    )
    if not any(marker in text for marker in serious_markers):
        return None
    if "자본주의사회에서진짜돈으로행복" in text and "믿어" in text:
        return None
    if _has_any(text, "구조선", "게시물", "눈팅", "호캉스", "현타", "들어갈래", "고를래", "할래", "은퇴하고나면", "어떤환경"):
        if not _has_any(text, "민주주의", "언론", "표현의자유", "다수결", "권리", "자유의지", "좋은사회"):
            return None

    if _has_any(text, "한국과중국과일본", "한중일") and _has_any(text, "뭉치", "하나"):
        return _shape_result(
            "한중일이 하나로 뭉치기 어려운 건 감정 문제가 아니라 역사 기억, 안보 이해관계, 경제 경쟁, 국내정치가 한꺼번에 걸려 있어서야. 가까운 만큼 협력할 이유도 큰데, 가까워서 더 예민하게 부딪히는 관계라고 봐.",
            "knowledge_geopolitics_explanation",
            "한국",
            "중국",
            "일본",
        )
    if "남북통일" in text:
        return _shape_result(
            "남북통일은 이상만 보면 매력적인데, 현실은 체제 차이, 비용, 안보, 주변국 이해관계가 너무 커. 그래서 나는 감정으로 밀기보다 단계별 신뢰와 생활 격차를 줄이는 쪽부터 봐야 한다고 생각해.",
            "knowledge_geopolitics_explanation",
            "남북통일",
        )

    if _has_any(text, "왕권", "의회"):
        return _shape_result(
            "왕권이 강한 나라는 결정을 빨리 밀 수 있지만 견제가 약해지기 쉽고, 의회가 강한 나라는 느리고 시끄러워도 권력을 나눠 잡는 힘이 있어. 결국 차이는 속도냐 견제냐의 문제에 가까워.",
            "knowledge_political_reflection",
            "왕권",
            "의회",
        )
    if _has_any(text, "왕이착", "독재"):
        return _shape_result(
            "왕이 착하다고 독재가 괜찮아지는 건 아니라고 봐. 좋은 사람이 잡은 절대권력도 다음 사람이 망가뜨리면 막을 장치가 없어서, 핵심은 사람의 선의보다 견제 구조야.",
            "knowledge_political_reflection",
            "독재",
        )
    if "포퓰리즘" in text:
        return _shape_result(
            "포퓰리즘은 사람들이 실제로 답답해하는 문제를 건드린다는 점에선 힘이 있어. 그런데 복잡한 문제를 적 하나로 단순화하고 분노만 키우면, 해결보다 동원에 가까워져서 위험해.",
            "knowledge_political_reflection",
            "포퓰리즘",
        )
    if _has_any(text, "국가가국민", "국가", "국민") and "책임" in text:
        return _shape_result(
            "국가는 국민의 인생을 대신 살아줄 순 없지만, 넘어졌을 때 끝장나지 않게 기본선은 책임져야 한다고 봐. 의료, 안전, 교육, 최소한의 생활 같은 바닥이 무너지면 개인 노력도 힘을 잃거든.",
            "knowledge_political_reflection",
            "국가",
            "국민",
            "책임",
        )
    if _has_any(text, "언론자유", "가짜뉴스"):
        return _shape_result(
            "언론 자유와 가짜뉴스 규제는 진짜 어려운 선이야. 나는 권력 비판은 넓게 열어두되, 조작된 사실로 사람을 해치거나 선거를 망가뜨리는 건 투명한 기준으로 제동을 걸어야 한다고 봐.",
            "knowledge_political_reflection",
            "언론 자유",
            "가짜뉴스",
        )

    if "음모론" in text:
        return _shape_result(
            "사람들이 음모론에 끌리는 건 세상이 너무 복잡하고 불안할 때, 차라리 누군가 조종하고 있다는 설명이 더 단순하고 덜 무섭게 느껴져서야. 문제는 그 단순함이 현실을 더 망칠 수 있다는 거지.",
            "knowledge_philosophy_position",
            "음모론",
        )
    if _has_any(text, "법이항상정의", "법은정의", "법이정의") and _has_any(text, "보장", "볼수", "항상"):
        return _shape_result(
            "법이 항상 정의를 보장하진 못해. 법은 사회가 합의한 최소 규칙인데, 그 합의가 늦거나 편향되면 합법인데도 부당한 일이 생기거든. 그래서 법과 정의는 붙어 있지만 같은 말은 아니야.",
            "knowledge_ethics_dilemma",
            "법",
            "정의",
        )
