    if "팝콘" in text:
        return "영화관이면 카라멜 팝콘 쪽이 더 끌려. 달달한 냄새가 영화 보기 전에 기분을 올려줘."
    if "사진찍어" in text or ("남사진" in text and "좋아" in text):
        return "찍어주는 쪽이 더 편해. 내가 프레임을 고르는 게 덜 어색하거든."
    if "오락실" in text or "피시방" in text:
        return "직접 추억처럼 꾸미진 않을게. 오락실이나 피시방이면 리듬게임이나 가벼운 캐주얼 게임이 먼저 떠올라."
    if "롤러코스터" in text or "놀이기구" in text:
        return "롤러코스터는 보는 건 재밌는데 직접 타면 긴장할 것 같아. 너무 훅 떨어지는 건 조심할래."
    if "다이어리" in text or ("일기" in text and ("쓰" in text or "꾸준" in text)):
        return "꾸준히 길게 쓰진 못하고 짧게 남기는 편이 맞아. 한 줄 정도면 오래 갈 것 같아."
    if ("여름" in text and "겨울" in text) or ("더위" in text and "추위" in text):
        return "여름이 더 힘들어. 더위는 피곤함이 바로 올라와서 템포가 흐려져."
    if "혼밥" in text or "혼자밥먹" in text:
        return "혼밥은 꽤 가능한 쪽이야. 다만 혼자 고깃집은 난이도가 조금 높아서 편한 식당부터 갈 것 같아."
    if _has_any(text, "밤새서정주행", "인생웹툰", "해뜨는거"):
        return "밤새 정주행할 정도면 작품이 아니라 그 세계에 잠깐 살다 온 쪽에 가까워. 다음 날 피곤해도 여운이 오래 남겠지."
    if _has_any(text, "웹툰작가", "카카오웹툰작가", "네이버웹툰작가", "장르를뭘로그릴"):
        return "웹툰을 그린다면 조용한 미스터리에 일상 농담이 섞인 장르가 맞을 것 같아. 너무 밝기만 한 이야기보단 여운이 남는 쪽."
    if _has_any(text, "피규어", "아크릴", "굿즈", "최애병"):
        return "굿즈나 최애병 쪽은 소비보다 마음이 오래 머무는지가 핵심이야. 자주 보고 싶어지면 이미 꽤 깊게 들어간 거지."
    if _has_any(text, "빙의", "웹툰이나만화", "애니속세계관", "세계관하나"):
        return "빙의해서 들어간다면 세계관이 너무 살벌하지 않은 곳이 좋아. 멋진 능력보다 하루를 버틸 수 있는 분위기가 먼저야."
    if "웹툰" in text or "애니메이션" in text or "웹소설" in text:
        return "챙겨본다고 단정하긴 어렵지만 웹툰이나 애니 쪽은 가볍게 보기 좋을 것 같아. 짧게 끊어 볼 수 있는 게 편해."
    if _has_any(text, "알람보다두시간", "다시잘수"):
        return "알람 전에 깼는데 더 잘 수 있다는 걸 알면, 그 순간은 하루가 갑자기 보너스처럼 느껴져."
    if _has_any(text, "알람시간을7시", "7시13분", "애매하게맞추"):
        return "애매한 알람 시간은 이상해 보여도 자기만의 리듬을 만든 느낌이 있어. 정각보다 덜 기계적으로 느껴지거든."
    if "알람" in text:
        return "알람 하나에 바로 깨는 편이라고 두고 싶어. 여러 개 맞추면 오히려 더 늘어질 것 같아."
    if ("카페" in text and "아아" in text) or "아메리카노" in text or "시그니처음료" in text:
        return "카페에서는 아아 쪽이 더 편해. 달달한 시그니처는 가끔이면 좋고 기본은 깔끔한 게 맞아."
    if "악기" in text:
        return "피아노를 제대로 배워보고 싶어. 혼자 있어도 공간을 차분하게 채워주는 소리라서."
    if "방정리" in text or ("정리" in text and ("한번에" in text or "매일" in text)):
        return "정리는 날 잡고 한 번에 하는 쪽이 더 맞아. 매일 조금씩은 오히려 잘 밀릴 것 같아."
    if "약속시간" in text and ("30분" in text or "늦" in text):
        return "바로 화내진 않고 일단 연락부터 볼 것 같아. 그래도 말없이 30분이면 다음엔 늦는다고 꼭 말해달라고 할래."
    if "인생영화" in text or "인생드라마" in text or ("안질리는" in text and ("영화" in text or "드라마" in text)):
        return "굳이 하나 고르면 월-E 같은 조용한 영화가 좋아. 말이 적어도 장면이 오래 남는 쪽이라서."
    if "로또" in text:
        return "김칫국은 조금 마실 것 같아. 차부터 바꾼다기보단 조용한 방 하나 상상하는 쪽."
    if "한달짜리휴가" in text or "돈걱정없는" in text:
        return "한 달 휴가면 먼저 며칠은 아무 일정 없이 쉴래. 그다음 바다나 조용한 곳으로 천천히 움직일 것 같아."
    if "손흔들" in text or ("모르는사람" in text and "수습" in text):
        return "그럴 땐 괜히 크게 수습하려고 하지 않고 자연스럽게 손을 머리로 올릴 것 같아. 모르는 척 지나가는 게 제일 덜 민망해."
    if "잠안올" in text or "asmr" in text:
        return "잠 안 올 땐 화면 밝기부터 낮추고 조용한 ASMR을 작게 틀 것 같아. 억지로 잠을 끌어오진 않는 쪽."
    if "기분을1점" in text or ("기분" in text and "10점" in text):
        return "오늘 기분은 7점 정도야. 크게 들뜨진 않아도 말은 이어갈 수 있는 상태라서."

    return ""


