def _render_forest_animal_direct_reply(user_text: str) -> str:
    text = _normalize(user_text)
    has_forest_topic = any(
        marker in text
        for marker in (
            "다람쥐",
            "청설모",
            "도토리",
            "독수리",
            "맹금류",
            "거미",
            "거미줄",
            "곤충",
            "독거미",
            "나무",
            "숲",
            "풀숲",
            "단풍",
            "은행나무",
            "정자나무",
            "트리하우스",
            "장작",
            "불멍",
        )
    )
    if not has_forest_topic:
        return ""

    if "다람쥐라면" in text and "도토리" in text:
        return "다람쥐라면 한곳에 몰아두진 않을 것 같아. 나무뿌리 근처랑 낙엽 밑에 나눠 숨길 듯해."
    if "다람쥐" in text and "도토리" in text:
        return "직접 봤다고 만들진 않을게. 그래도 볼 빵빵하게 도토리 먹는 장면이면 꽤 귀엽게 남을 것 같아."
    if "청설모" in text:
        return "청설모는 다람쥐보다 더 날렵하고 낯선 느낌이 있어. 꼬리 색 때문에 한 번 더 보게 될 것 같아."
    if "다람쥐" in text and ("꼬리" in text or "쓰다듬" in text):
        return "쓰다듬어 보고 싶은 마음은 들겠지만 가까이 가진 않을래. 동물 입장에선 도망갈 거리도 필요하니까."
    if "다람쥐" in text and ("양볼" in text or "오물오물" in text):
        return "그건 귀여운 쪽에 가까워. 양볼 가득 먹는 모습이면 분위기가 바로 풀릴 것 같아."
    if "먹이" in text and "다람쥐" in text:
        return "가까이 다가가서 먹이는 주지 않는 쪽이 맞아. 멀리서 보는 편이 서로 덜 부담돼."
    if "다람쥐" in text and ("쳇바퀴" in text or "일상이반복" in text):
        return "그럴 땐 큰 변화보다 루틴 하나만 바꾸는 게 낫겠어. 산책길이나 음악부터 살짝 바꿔보는 식으로."

    if "독수리처럼" in text and ("날아서" in text or "높이날" in text):
        return "그렇게 높이 날면 시야는 확 열리겠지만 조금 무서울 것 같아. 그래도 답답함은 바로 풀리겠지."
