def _render_transport_destination_preference_reply(user_text: str) -> str:
    text = _normalize(user_text)
    if not text:
        return ""
    if not _has_any(text, "어디로", "어디가", "어디를"):
        return ""
    if not _has_any(text, "가고싶", "떠나고싶", "갈래"):
        return ""
    if _has_any(text, "지하철", "전철"):
        return "지하철이면 한강 쪽이나 오래 걸어도 부담 없는 동네로 갈래. 목적지보다 창밖 보면서 천천히 이동하는 느낌이 좋아."
    if _has_any(text, "기차", "ktx"):
        return "기차면 바다 보이는 도시로 갈래. 도착보다 가는 동안 멍하니 흔들리는 시간이 더 좋아."
    if "버스" in text:
        return "버스라면 종점 가까운 낯선 동네로 가보고 싶어. 크게 계획하지 않고 창밖 보다가 내리는 쪽이 좋아."
    if "비행기" in text:
        return "비행기라면 너무 빽빽한 도시보다 조용한 바닷가 쪽으로 갈래. 멀리 갔다는 느낌이 분명한 곳이 좋아."
    return ""


