@lru_cache(maxsize=32768)
def _normalize(text: str) -> str:
    return re.sub(r"[^0-9A-Za-z가-힣]+", "", str(text or "")).lower()


def _safe_topic_anchor(anchor: str, user_text: str) -> str:
    anchor_text = _compact(re.sub(r"[.!?。]+$", "", anchor or ""), 28)
    if not anchor_text or _bad_topic_anchor(anchor_text, user_text=user_text):
        return "그 말"
    if re.search(r"(?:는데|은데|한데|인데|던데|지만)$", anchor_text):
        return "그 말"
    if len(_normalize(anchor_text)) > 18 or _normalize(anchor_text) == _normalize(user_text):
        return "그 말"
    return anchor_text


def _topic_subject(anchor: str, user_text: str, *, fallback: str) -> str:
    topic = _safe_topic_anchor(anchor, user_text)
    if topic == "그 말":
        topic = fallback
    if topic.endswith(("은", "는", "이", "가")):
        return topic
    return f"{topic}{_topic_marker(topic)}"


def _topic_marker(text: str) -> str:
    if re.search(r"[A-Za-z0-9]$", str(text or "").strip()):
        return "는"
    return "은" if _has_final_consonant(text) else "는"


def _if_marker(text: str) -> str:
    return "이면" if _has_final_consonant(text) else "면"


def _subject_marker(text: str) -> str:
    return "이" if _has_final_consonant(text) else "가"


def _and_marker(text: str) -> str:
    return "이랑" if _has_final_consonant(text) else "랑"


def _object_marker(text: str) -> str:
    return "을" if _has_final_consonant(text) else "를"


def _has_final_consonant(text: str) -> bool:
    cleaned = re.sub(r"[^가-힣]+", "", str(text or ""))
    if not cleaned:
        return False
    code = ord(cleaned[-1])
    if not 0xAC00 <= code <= 0xD7A3:
        return False
    return (code - 0xAC00) % 28 != 0


def _bad_topic_anchor(anchor: str, *, user_text: str) -> bool:
    normalized = _normalize(anchor)
    if not normalized:
        return False
    if normalized in INTERNAL_MUST_INCLUDE_LABELS:
        return True
    if normalized == "놀거리" and not any(
        marker in _normalize(user_text) for marker in ("놀", "활동", "뭐하면서", "뭐할래", "머할래", "뭐하지", "머하지")
    ):
        return True
    if any(marker in normalized for marker in INSTRUCTION_FRAGMENT_MARKERS):
        return True
    if _looks_like_numbered_fragment(anchor):
        return True
    if "|" in anchor or "\n" in anchor:
        return True
    if "쪽이" in anchor:
        return True
    if normalized == _normalize(user_text):
        return True
    if len(normalized) > 24:
        return True
    return bool(re.search(r"[?？!！]$", anchor.strip()))


def _looks_like_bad_must_include_item(item: str, *, user_text: str, anchor: str) -> bool:
    normalized = _normalize(item)
    user_norm = _normalize(user_text)
    if normalized in INTERNAL_MUST_INCLUDE_LABELS:
        return True
    if normalized == "놀거리" and not any(
        marker in _normalize(user_text) for marker in ("놀", "활동", "뭐하면서", "뭐할래", "머할래", "뭐하지", "머하지")
    ):
        return True
    if normalized in user_norm and _looks_like_surface_phrase_hint(normalized):
        return True
    if any(marker in normalized for marker in INSTRUCTION_FRAGMENT_MARKERS):
        return True
    if _looks_like_numbered_fragment(item):
        return True
    if "|" in item or "\n" in item:
        return True
    if re.search(r"(?:^|\s)\d+[.)]\s*", item):
        return True
    if len(normalized) >= 18 and (normalized in user_norm or normalized in _normalize(anchor)):
        return True
    if len(normalized) > 24 and any(marker in item for marker in (".", "?", "!", "。")):
        return True
    if any(marker in normalized for marker in ("틀어야한다면", "어떤쪽", "이런곡", "이런후보", "헤드라인")):
        return True
    if normalized in {"뭐가", "무엇", "느낌", "말투", "쪽이"}:
        return True
    if any(mark in item for mark in ("?", ".", "!")) and normalized in user_norm:
        return True
    return False


def _looks_like_surface_phrase_hint(normalized: str) -> bool:
    return any(
        marker in normalized
        for marker in (
            "하는거",
            "보는거",
            "먹는거",
            "타는거",
            "가는거",
            "하고놀",
            "뭐하지",
            "뭐하면",
            "뭐부터",
            "할만한거",
            "필요한거",
            "확인할거",
        )
    )


def _looks_like_numbered_fragment(text: str) -> bool:
    stripped = str(text or "").strip()
    return bool(re.fullmatch(r"\d+[.)]?", stripped) or re.search(r"\b\d+[.)]\s*$", stripped))


def _pick_music_title(anchor: str, must_include: list[str]) -> str:
    for raw in [*must_include, anchor]:
        for part in re.split(r"[|\n]+", raw):
            title = re.sub(r"^\s*\d+[.)]\s*", "", part).strip(" -")
            if not title or _normalize(title) in INTERNAL_MUST_INCLUDE_LABELS:
                continue
            normalized = _normalize(title)
            if normalized in {"쪽이", "음악", "노래", "곡"}:
                continue
            if raw == anchor and any(marker in normalized for marker in ("음악", "노래", "곡")):
                continue
            if any(marker in normalized for marker in ("틀어야한다면", "어떤쪽", "어떤느낌", "고를때")):
                continue
            if len(_normalize(title)) < 2:
                continue
            return _compact(title, 80)
    return ""


def _looks_like_named_media_or_music_title(item: str) -> bool:
    raw = str(item or "")
    if " - " in raw and re.search(r"[A-Za-z가-힣]", raw):
        return True
    return bool("," in raw and re.search(r"[A-Za-z]", raw) and re.search(r"[가-힣]", raw))


def _pick_media_title(anchor: str, must_include: list[str]) -> str:
    for raw in [*must_include, anchor]:
        for part in re.split(r"[|\n,]+", raw):
            title = re.sub(r"^\s*\d+[.)]\s*", "", part).strip(" -")
            if not title or _normalize(title) in INTERNAL_MUST_INCLUDE_LABELS:
                continue
            if _normalize(title) in {"media", "recommend", "recommendation", "코미디", "영화", "드라마", "예능", "애니", "웹툰"}:
                continue
            if any(marker in _normalize(title) for marker in ("이런후보", "짧게말해줘", "어떤느낌")):
                continue
            if len(_normalize(title)) < 2:
                continue
            return _compact(title, 32)
    return ""
